{
  "name": "Gestor de Relatórios de Licenças",
  "description": "Uma aplicação profissional para gerar relatórios de entrega de licenças de software com auxílio de IA para redação formal.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface LicenseItem {
  id: string;
  software: string;
  version: string;
  key: string;
  quantity: number;
  expiryDate?: string;
}

export interface ReportData {
  reportNumber: string;
  date: string;
  senderName: string;
  senderCompany: string;
  recipientName: string;
  recipientCompany: string;
  objective: string;
  observations: string;
  items: LicenseItem[];
}

import { GoogleGenAI, Type } from "@google/genai";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const improveDescription = async (text: string, type: 'objective' | 'observations'): Promise<string> => {
  const ai = getAI();
  const prompt = type === 'objective' 
    ? `Melhore o seguinte objetivo de entrega de licenças de software para um tom mais formal e profissional em português brasileiro. Mantenha-o conciso: "${text}"`
    : `Melhore as seguintes observações de um relatório de entrega de licenças. Transforme anotações informais em um parágrafo profissional e estruturado em português brasileiro: "${text}"`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text?.trim() || text;
  } catch (error) {
    console.error("Erro ao processar com Gemini:", error);
    return text;
  }
};

export const generateSummary = async (items: any[]): Promise<string> => {
  const ai = getAI();
  const itemsText = items.map(i => `${i.quantity}x ${i.software} (Versão: ${i.version})`).join(', ');
  const prompt = `Gere uma breve conclusão formal em português para um relatório que está entregando as seguintes licenças: ${itemsText}. Fale sobre a importância da conformidade e uso correto.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text?.trim() || "";
  } catch (error) {
    console.error("Erro ao gerar resumo:", error);
    return "";
  }
};

import React, { useState, useCallback } from 'react';
import { PlusIcon, TrashIcon, SparklesIcon, PrinterIcon, ArrowPathIcon } from '@heroicons/react/24/outline';
import { LicenseItem, ReportData } from './types';
import { improveDescription, generateSummary } from './services/gemini';
import ReportPreview from './components/ReportPreview';

const initialData: ReportData = {
  reportNumber: `REL-${new Date().getFullYear()}-${Math.floor(Math.random() * 1000).toString().padStart(3, '0')}`,
  date: new Date().toISOString().split('T')[0],
  senderName: '',
  senderCompany: '',
  recipientName: '',
  recipientCompany: '',
  objective: 'Entrega formal de licenças de software adquiridas para uso corporativo.',
  observations: '',
  items: [
    { id: '1', software: '', version: '', key: '', quantity: 1 }
  ]
};

const App: React.FC = () => {
  const [data, setData] = useState<ReportData>(initialData);
  const [loadingAI, setLoadingAI] = useState<boolean>(false);
  const [showPreview, setShowPreview] = useState<boolean>(false);

  const handleUpdateItem = (id: string, field: keyof LicenseItem, value: any) => {
    setData(prev => ({
      ...prev,
      items: prev.items.map(item => item.id === id ? { ...item, [field]: value } : item)
    }));
  };

  const addItem = () => {
    setData(prev => ({
      ...prev,
      items: [...prev.items, { id: Date.now().toString(), software: '', version: '', key: '', quantity: 1 }]
    }));
  };

  const removeItem = (id: string) => {
    if (data.items.length === 1) return;
    setData(prev => ({
      ...prev,
      items: prev.items.filter(item => item.id !== id)
    }));
  };

  const handleImproveText = async (field: 'objective' | 'observations') => {
    if (!data[field]) return;
    setLoadingAI(true);
    const improved = await improveDescription(data[field], field);
    setData(prev => ({ ...prev, [field]: improved }));
    setLoadingAI(false);
  };

  const handleAutoConclusion = async () => {
    setLoadingAI(true);
    const conclusion = await generateSummary(data.items);
    setData(prev => ({ ...prev, observations: prev.observations + "\n\nConclusão sugerida pela IA:\n" + conclusion }));
    setLoadingAI(false);
  };

  if (showPreview) {
    return (
      <div className="min-h-screen bg-white">
        <div className="no-print p-4 bg-slate-800 text-white flex justify-between items-center sticky top-0 z-50">
          <h1 className="font-bold">Pré-visualização do Relatório</h1>
          <div className="space-x-4">
            <button 
              onClick={() => setShowPreview(false)}
              className="px-4 py-2 bg-slate-600 rounded hover:bg-slate-700 transition"
            >
              Voltar à Edição
            </button>
            <button 
              onClick={() => window.print()}
              className="px-4 py-2 bg-blue-600 rounded hover:bg-blue-700 transition flex items-center gap-2"
            >
              <PrinterIcon className="w-5 h-5" /> Imprimir / PDF
            </button>
          </div>
        </div>
        <div className="max-w-4xl mx-auto p-8 shadow-lg my-8 print:shadow-none print:my-0">
          <ReportPreview data={data} />
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      <header className="bg-white border-b px-6 py-4 flex justify-between items-center sticky top-0 z-40">
        <div className="flex items-center gap-3">
          <div className="bg-blue-600 p-2 rounded-lg">
            <SparklesIcon className="w-6 h-6 text-white" />
          </div>
          <h1 className="text-xl font-bold text-slate-800">Gerador de Relatório de Licenças</h1>
        </div>
        <button 
          onClick={() => setShowPreview(true)}
          className="bg-blue-600 text-white px-6 py-2 rounded-full font-semibold hover:bg-blue-700 transition-all flex items-center gap-2"
        >
          <PrinterIcon className="w-5 h-5" /> Gerar Relatório
        </button>
      </header>

      <main className="max-w-5xl mx-auto mt-8 px-4 grid grid-cols-1 md:grid-cols-3 gap-8">
        {/* Left Column: Config */}
        <section className="md:col-span-1 space-y-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <h2 className="text-lg font-semibold mb-4 border-b pb-2">Informações Gerais</h2>
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Nº do Relatório</label>
                <input 
                  type="text" 
                  value={data.reportNumber}
                  onChange={(e) => setData(prev => ({ ...prev, reportNumber: e.target.value }))}
                  className="w-full border rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Data</label>
                <input 
                  type="date" 
                  value={data.date}
                  onChange={(e) => setData(prev => ({ ...prev, date: e.target.value }))}
                  className="w-full border rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 outline-none"
                />
              </div>
            </div>
          </div>

          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <h2 className="text-lg font-semibold mb-4 border-b pb-2">Partes Envolvidas</h2>
            <div className="space-y-4">
              <div>
                <h3 className="text-xs font-bold uppercase text-slate-400 mb-2">Remetente (Emissor)</h3>
                <input 
                  placeholder="Nome do Responsável" 
                  className="w-full border rounded-lg px-3 py-2 mb-2 focus:ring-2 focus:ring-blue-500 outline-none"
                  value={data.senderName}
                  onChange={(e) => setData(prev => ({ ...prev, senderName: e.target.value }))}
                />
                <input 
                  placeholder="Nome da Empresa" 
                  className="w-full border rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 outline-none"
                  value={data.senderCompany}
                  onChange={(e) => setData(prev => ({ ...prev, senderCompany: e.target.value }))}
                />
              </div>
              <div className="pt-2">
                <h3 className="text-xs font-bold uppercase text-slate-400 mb-2">Destinatário (Receptor)</h3>
                <input 
                  placeholder="Nome do Destinatário" 
                  className="w-full border rounded-lg px-3 py-2 mb-2 focus:ring-2 focus:ring-blue-500 outline-none"
                  value={data.recipientName}
                  onChange={(e) => setData(prev => ({ ...prev, recipientName: e.target.value }))}
                />
                <input 
                  placeholder="Empresa/Departamento" 
                  className="w-full border rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 outline-none"
                  value={data.recipientCompany}
                  onChange={(e) => setData(prev => ({ ...prev, recipientCompany: e.target.value }))}
                />
              </div>
            </div>
          </div>
        </section>

        {/* Right Column: Items and Narrative */}
        <section className="md:col-span-2 space-y-6">
          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
            <div className="flex justify-between items-center mb-4">
              <h2 className="text-lg font-semibold">Licenças a Entregar</h2>
              <button 
                onClick={addItem}
                className="text-blue-600 hover:text-blue-800 flex items-center gap-1 text-sm font-bold"
              >
                <PlusIcon className="w-4 h-4" /> Adicionar Software
              </button>
            </div>

            <div className="space-y-4">
              {data.items.map((item, index) => (
                <div key={item.id} className="p-4 bg-slate-50 rounded-lg border border-slate-100 relative group">
                  <div className="grid grid-cols-12 gap-3">
                    <div className="col-span-6">
                      <label className="text-[10px] font-bold text-slate-400 uppercase">Software</label>
                      <input 
                        className="w-full border-none bg-transparent font-medium focus:ring-0 outline-none p-0"
                        placeholder="Ex: Microsoft Office 2024"
                        value={item.software}
                        onChange={(e) => handleUpdateItem(item.id, 'software', e.target.value)}
                      />
                    </div>
                    <div className="col-span-3">
                      <label className="text-[10px] font-bold text-slate-400 uppercase">Versão</label>
                      <input 
                        className="w-full border-none bg-transparent text-sm focus:ring-0 outline-none p-0"
                        placeholder="Versão"
                        value={item.version}
                        onChange={(e) => handleUpdateItem(item.id, 'version', e.target.value)}
                      />
                    </div>
                    <div className="col-span-3">
                      <label className="text-[10px] font-bold text-slate-400 uppercase">Qtd</label>
                      <input 
                        type="number"
                        className="w-full border-none bg-transparent text-sm focus:ring-0 outline-none p-0"
                        value={item.quantity}
                        onChange={(e) => handleUpdateItem(item.id, 'quantity', parseInt(e.target.value))}
                      />
                    </div>
                    <div className="col-span-12 mt-2 pt-2 border-t border-slate-200">
                      <label className="text-[10px] font-bold text-slate-400 uppercase">Chave de Licença / Código de Ativação</label>
                      <input 
                        className="w-full border-none bg-transparent text-xs font-mono focus:ring-0 outline-none p-0 text-slate-600"
                        placeholder="Insira a chave aqui..."
                        value={item.key}
                        onChange={(e) => handleUpdateItem(item.id, 'key', e.target.value)}
                      />
                    </div>
                  </div>
                  {data.items.length > 1 && (
                    <button 
                      onClick={() => removeItem(item.id)}
                      className="absolute -right-2 -top-2 bg-white border border-red-200 p-1 rounded-full text-red-500 opacity-0 group-hover:opacity-100 transition shadow-sm"
                    >
                      <TrashIcon className="w-4 h-4" />
                    </button>
                  )}
                </div>
              ))}
            </div>
          </div>

          <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 space-y-6">
            <div>
              <div className="flex justify-between items-center mb-2">
                <h2 className="text-lg font-semibold">Objetivo da Entrega</h2>
                <button 
                  disabled={loadingAI}
                  onClick={() => handleImproveText('objective')}
                  className="text-indigo-600 flex items-center gap-1 text-xs font-bold bg-indigo-50 px-2 py-1 rounded hover:bg-indigo-100 disabled:opacity-50"
                >
                  {loadingAI ? <ArrowPathIcon className="w-3 h-3 animate-spin" /> : <SparklesIcon className="w-3 h-3" />}
                  Polir com IA
                </button>
              </div>
              <textarea 
                className="w-full border rounded-lg p-3 text-sm focus:ring-2 focus:ring-blue-500 outline-none min-h-[80px]"
                value={data.objective}
                onChange={(e) => setData(prev => ({ ...prev, objective: e.target.value }))}
                placeholder="Descreva o propósito deste relatório..."
              />
            </div>

            <div>
              <div className="flex justify-between items-center mb-2">
                <h2 className="text-lg font-semibold">Observações / Termos</h2>
                <div className="flex gap-2">
                  <button 
                    disabled={loadingAI}
                    onClick={handleAutoConclusion}
                    className="text-green-600 flex items-center gap-1 text-xs font-bold bg-green-50 px-2 py-1 rounded hover:bg-green-100 disabled:opacity-50"
                  >
                    <SparklesIcon className="w-3 h-3" /> Sugerir Conclusão
                  </button>
                  <button 
                    disabled={loadingAI}
                    onClick={() => handleImproveText('observations')}
                    className="text-indigo-600 flex items-center gap-1 text-xs font-bold bg-indigo-50 px-2 py-1 rounded hover:bg-indigo-100 disabled:opacity-50"
                  >
                    {loadingAI ? <ArrowPathIcon className="w-3 h-3 animate-spin" /> : <SparklesIcon className="w-3 h-3" />}
                    Polir com IA
                  </button>
                </div>
              </div>
              <textarea 
                className="w-full border rounded-lg p-3 text-sm focus:ring-2 focus:ring-blue-500 outline-none min-h-[120px]"
                value={data.observations}
                onChange={(e) => setData(prev => ({ ...prev, observations: e.target.value }))}
                placeholder="Adicione observações adicionais, termos de uso ou prazos..."
              />
            </div>
          </div>
        </section>
      </main>
    </div>
  );
};

export default App;

