import React, { useState } from 'react';
import { PlusIcon, TrashIcon, SparklesIcon, PrinterIcon, ArrowPathIcon, DocumentTextIcon } from '@heroicons/react/24/outline';
import { LicenseItem, ReportData } from './types';
import { improveDescription } from './services/gemini';
import ReportPreview from './components/ReportPreview';
import SmartTechLogo from './components/SmartTechLogo';

const initialData: ReportData = {
  reportNumber: '001/2025',
  processRef: 'Processo Licitatório nº 084/2025',
  pregaoRef: 'Pregão Eletrônico nº 046/2025',
  contractRef: 'Contrato nº 001/2025',
  date: new Date().toISOString().split('T')[0],
  contratante: {
    name: 'PREFEITURA MUNICIPAL DE IPANEMA/MG',
    address: 'Avenida Sete de Setembro, nº 2155 – Bairro Centro, CEP 36.950-000 – MG',
    cnpj: '18.334.292/0001-64',
    representative: 'Júlio Fontoura de Moraes Júnior',
    cpf: '024.587.797-51'
  },
  contratada: {
    name: 'SMART EDU LTDA',
    address: 'Rua Coronel Constantino, nº 130 – Bairro Tabajaras, Uberlândia/MG, CEP 38.400-222',
    cnpj: '52.625.847/0001-65',
    representative: 'Carlos Henrique da Costa Carvalho',
    cpf: '060.541.786-52'
  },
  softwareDescription: 'software de gerenciamento integrado de dados educacionais (Frequência Escolar Facial e Web Ponto)',
  items: [
    { 
      id: '1', 
      category: 'ALUNOS', 
      quantity: '2.991', 
      key: '102025-100FGE-RMG', 
      description: 'Licença de aquisição perpétua de sistema informatizado, por aluno, para gerenciamento dos dados relativos à presença registrada nos dispositivos de autenticação da face e à educação municipal, com acesso via web, aplicação mobile para comunicação e consultas.' 
    }
  ],
  techResponsible: { name: 'Antônio Alves Reis Neto', rg: '862086' },
  installation: { environment: 'Cloud', restrictedTo: 'Secretaria Municipal de Educação de Ipanema/MG', accessLink: 'https://ipanema.pontoid.com.br/' },
  credentials: { username: '02549389140.ipanema', password: '02549389140', city: 'Ipanema / MG' }
};

const App: React.FC = () => {
  const [data, setData] = useState<ReportData>(initialData);
  const [loadingAI, setLoadingAI] = useState(false);
  const [showPreview, setShowPreview] = useState(false);

  const handleUpdate = (path: string, value: any) => {
    const keys = path.split('.');
    setData(prev => {
      const newData = { ...prev };
      let current: any = newData;
      for (let i = 0; i < keys.length - 1; i++) {
        current = current[keys[i]];
      }
      current[keys[keys.length - 1]] = value;
      return newData;
    });
  };

  const addItem = () => {
    setData(prev => ({
      ...prev,
      items: [...prev.items, { id: Date.now().toString(), category: '', quantity: '', key: '', description: '' }]
    }));
  };

  const removeItem = (id: string) => {
    setData(prev => ({ ...prev, items: prev.items.filter(item => item.id !== id) }));
  };

  const handleImproveSoftwareDesc = async () => {
    setLoadingAI(true);
    const improved = await improveDescription(data.softwareDescription, 'objective');
    handleUpdate('softwareDescription', improved);
    setLoadingAI(false);
  };

  if (showPreview) {
    return (
      <div className="min-h-screen bg-slate-100 p-0 md:p-8">
        <div className="no-print mb-6 max-w-4xl mx-auto flex justify-between items-center bg-slate-800 text-white p-4 rounded-lg shadow-xl">
          <div className="flex items-center gap-3">
            <DocumentTextIcon className="w-6 h-6 text-red-400" />
            <span className="font-bold">Termo de Entrega Profissional</span>
          </div>
          <div className="flex gap-3">
            <button onClick={() => setShowPreview(false)} className="px-4 py-2 bg-slate-700 hover:bg-slate-600 rounded-md transition text-sm">Voltar</button>
            <button onClick={() => window.print()} className="px-6 py-2 bg-red-600 hover:bg-red-700 rounded-md transition text-sm font-bold flex items-center gap-2">
              <PrinterIcon className="w-4 h-4" /> Imprimir Termo
            </button>
          </div>
        </div>
        <div className="max-w-[210mm] mx-auto shadow-2xl bg-white">
          <ReportPreview data={data} />
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 font-sans">
      {/* Subtle Background Watermark */}
      <div className="fixed inset-0 opacity-[0.03] pointer-events-none flex items-center justify-center overflow-hidden">
        <SmartTechLogo className="scale-[10] grayscale" />
      </div>

      <header className="bg-slate-800/50 backdrop-blur-md border-b border-slate-700 px-8 py-4 sticky top-0 z-50 flex justify-between items-center">
        <SmartTechLogo className="h-10 invert brightness-200" />
        <div className="flex items-center gap-4">
          <button 
            onClick={() => setShowPreview(true)}
            className="bg-red-600 hover:bg-red-700 text-white px-8 py-2.5 rounded-lg font-bold transition-all transform hover:scale-105 shadow-lg shadow-red-900/20 flex items-center gap-2"
          >
            <PrinterIcon className="w-5 h-5" /> Visualizar e Imprimir
          </button>
        </div>
      </header>

      <main className="max-w-6xl mx-auto p-8 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Left column: References and Entities */}
        <div className="lg:col-span-4 space-y-6">
          <div className="bg-slate-800 border border-slate-700 p-6 rounded-2xl shadow-xl">
            <h2 className="text-red-400 font-bold text-sm uppercase tracking-widest mb-4 flex items-center gap-2">
              <DocumentTextIcon className="w-4 h-4" /> Referências do Documento
            </h2>
            <div className="space-y-4">
              <Input label="Número do Termo" value={data.reportNumber} onChange={v => handleUpdate('reportNumber', v)} />
              <Input label="Processo Licitatório" value={data.processRef} onChange={v => handleUpdate('processRef', v)} />
              <Input label="Pregão Eletrônico" value={data.pregaoRef} onChange={v => handleUpdate('pregaoRef', v)} />
              <Input label="Contrato" value={data.contractRef} onChange={v => handleUpdate('contractRef', v)} />
            </div>
          </div>

          <div className="bg-slate-800 border border-slate-700 p-6 rounded-2xl shadow-xl">
            <h2 className="text-red-400 font-bold text-sm uppercase tracking-widest mb-4">A Contratante</h2>
            <div className="space-y-4">
              <Input label="Órgão/Prefeitura" value={data.contratante.name} onChange={v => handleUpdate('contratante.name', v)} />
              <Input label="CNPJ" value={data.contratante.cnpj} onChange={v => handleUpdate('contratante.cnpj', v)} />
              <Input label="Representante Legal" value={data.contratante.representative} onChange={v => handleUpdate('contratante.representative', v)} />
              <Input label="CPF do Representante" value={data.contratante.cpf} onChange={v => handleUpdate('contratante.cpf', v)} />
            </div>
          </div>
        </div>

        {/* Center/Right column: Main content */}
        <div className="lg:col-span-8 space-y-6">
          <div className="bg-slate-800 border border-slate-700 p-6 rounded-2xl shadow-xl">
            <div className="flex justify-between items-center mb-4">
              <h2 className="text-red-400 font-bold text-sm uppercase tracking-widest">Descrição do Software</h2>
