                        <button onClick={() => handleUpdate('items', [...data.items, { id: Date.now().toString(), category: 'NOVO', quantity: '0', key: '...', description: '' }])} className="text-[#E30613] font-black text-[10px] uppercase tracking-widest flex items-center gap-1 hover:scale-105 transition-transform">
