                              const ni = [...data.items]; ni[idx].category = v; handleUpdate('items', ni);
                            }} /></div>
                            <div className="md:col-span-2"><FormInput label="Qtd" value={item.quantity} onChange={v => {
                              const ni = [...data.items]; ni[idx].quantity = v; handleUpdate('items', ni);
                            }} /></div>
                            <div className="md:col-span-6"><FormInput label="Chave Serial" value={item.key} onChange={v => {
                              const ni = [...data.items]; ni[idx].key = v; handleUpdate('items', ni);
                            }} /></div>
                            <div className="md:col-span-12">
                              <label className="text-[10px] font-black text-white/20 uppercase tracking-widest mb-3 block">Descrição da Licença</label>
                              <textarea 
                                className="w-full bg-black/20 border border-white/5 rounded-2xl p-4 text-sm text-white/60 focus:border-[#E30613]/30 outline-none h-24"
                                value={item.description}
                                onChange={(e) => {
                                  const ni = [...data.items]; ni[idx].description = e.target.value; handleUpdate('items', ni);
                                }}
                              />
                            </div>
                          </div>
                          <button onClick={() => handleUpdate('items', data.items.filter(i => i.id !== item.id))} className="absolute -top-3 -right-3 bg-[#E30613] text-white p-2.5 rounded-full opacity-0 group-hover:opacity-100 shadow-xl transition-all scale-75 group-hover:scale-100">
                            <TrashIcon className="w-4 h-4" />
                          </button>
                        </div>
                      ))}
                    </div>
                  </div>
                )}

                {activeTab === 'Instalacao' && (
                  <CardSection title="Infraestrutura" subtitle="Configurações de rede e acesso técnico">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                      <FormInput label="Responsável Smart Tech" value={data.techResponsible.name} onChange={v => handleUpdate('techResponsible.name', v)} />
                      <FormInput label="Link Endpoint" value={data.installation.accessLink} onChange={v => handleUpdate('installation.accessLink', v)} />
                      <FormInput label="Login Padrão" value={data.credentials.username} onChange={v => handleUpdate('credentials.username', v)} />
                      <FormInput label="Senha Temporária" value={data.credentials.password} onChange={v => handleUpdate('credentials.password', v)} />
                    </div>
                  </CardSection>
                )}
              </div>
            )}
          </div>
        </main>
      </div>
    </div>
  );
};

// Sub-components for cleaner App.tsx
const NavItem: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string }> = ({ active, onClick, icon, label }) => (
  <button 
    onClick={onClick}
    className={`w-full flex items-center gap-4 px-5 py-4 rounded-2xl transition-all duration-300 group ${
      active 
      ? 'bg-gradient-to-r from-[#E30613] to-[#ff3b47] text-white shadow-lg shadow-red-600/30 font-bold' 
      : 'text-white/30 hover:text-white hover:bg-white/5 font-medium'
    }`}
  >
    <div className={`w-5 h-5 transition-transform duration-300 ${active ? 'scale-110' : 'group-hover:scale-110 opacity-60 group-hover:opacity-100'}`}>
      {icon}
