  </button>
);

const CardSection: React.FC<{ title: string; subtitle: string; children: React.ReactNode }> = ({ title, subtitle, children }) => (
  <section className="bg-white/5 border border-white/5 p-10 rounded-[40px] shadow-2xl backdrop-blur-sm">
    <div className="mb-10">
      <h2 className="text-xl font-black text-white tracking-tight mb-1">{title}</h2>
      <p className="text-sm text-white/30 font-medium">{subtitle}</p>
    </div>
    {children}
  </section>
);

const FormInput: React.FC<{ label: string; value: string; onChange: (v: string) => void; type?: string }> = ({ label, value, onChange, type = "text" }) => (
  <div className="space-y-2 group">
    <label className="text-[10px] font-black text-white/20 uppercase tracking-[0.2em] ml-1 group-focus-within:text-[#E30613] transition-colors">
      {label}
    </label>
    <input 
      type={type}
      value={value}
      onChange={(e) => onChange(e.target.value)}
      className="w-full bg-black/40 border border-white/5 rounded-2xl px-5 py-4 text-sm text-white/90 focus:border-[#E30613]/40 outline-none transition-all focus:ring-2 ring-[#E30613]/10"
    />
  </div>
);

export default App;

