  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'success'>('idle');
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const stored = localStorage.getItem(DB_KEY);
    if (stored) {
      try {
        setSavedReports(JSON.parse(stored));
      } catch (e) { console.error(e); }
    }
  }, []);

  const saveToDatabase = () => {
    setSaveStatus('saving');
    const updatedReports = [...savedReports];
    const index = updatedReports.findIndex(r => r.id === data.id);
    index >= 0 ? (updatedReports[index] = data) : updatedReports.unshift(data);
    localStorage.setItem(DB_KEY, JSON.stringify(updatedReports));
    setSavedReports(updatedReports);
    setTimeout(() => {
      setSaveStatus('success');
      setTimeout(() => setSaveStatus('idle'), 2000);
    }, 400);
  };

  const handlePrint = () => {
    const originalTitle = document.title;
    document.title = `Termo_${data.reportNumber.replace(/\//g, '-')}_${data.contratante.name.split(' ')[0]}`;
    window.print();
    document.title = originalTitle;
  };

  const exportCurrentReport = () => {
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `Termo_${data.reportNumber.replace(/\//g, '-')}.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const exportDB = () => {
    const blob = new Blob([JSON.stringify(savedReports, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `smart_tech_backup_completo_${new Date().toISOString().split('T')[0]}.json`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const importDB = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const json = JSON.parse(e.target?.result as string);
        if (Array.isArray(json)) {
          if (confirm(`Deseja importar ${json.length} relatórios? Isso substituirá o banco atual.`)) {
            setSavedReports(json);
            localStorage.setItem(DB_KEY, JSON.stringify(json));
            if (json.length > 0) setData(json[0]);
          }
        } else {
          alert("Arquivo inválido. Formato não suportado.");
        }
      } catch (err) {
        alert("Erro ao ler o arquivo JSON.");
      }
    };
    reader.readAsText(file);
  };

  const createNewReport = () => {
    setData({
      ...initialData,
      id: Date.now().toString(),
      reportNumber: `${savedReports.length + 1}/2025`,
      date: new Date().toISOString().split('T')[0]
    });
    setActiveTab('Geral');
  };

  const loadReport = (report: ReportData) => {
    setData(report);
    setActiveTab('Geral');
  };

  const deleteReport = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm("Deseja excluir permanentemente?")) {
      const filtered = savedReports.filter(r => r.id !== id);
      setSavedReports(filtered);
      localStorage.setItem(DB_KEY, JSON.stringify(filtered));
      if (data.id === id) createNewReport();
    }
  };

  const handleUpdate = (path: string, value: any) => {
    const keys = path.split('.');
    setData(prev => {
      const newData = { ...prev };
      let current: any = newData;
      for (let i = 0; i < keys.length - 1; i++) current = current[keys[i]];
      current[keys[keys.length - 1]] = value;
      return newData;
    });
  };

  const handleImproveSoftwareDesc = async () => {
    setLoadingAI(true);
    const improved = await improveDescription(data.softwareDescription, 'objective');
    handleUpdate('softwareDescription', improved);
    setLoadingAI(false);
  };

