            <button onClick={() => setShowPreview(false)} className="px-6 py-2.5 text-white/60 hover:text-white transition-all text-sm font-bold bg-white/5 hover:bg-white/10 rounded-full border border-white/5">
              Voltar ao Editor
            </button>
            <button onClick={handlePrint} className="bg-[#E30613] hover:bg-[#ff0714] text-white px-8 py-2.5 rounded-full transition-all flex items-center gap-2 shadow-2xl shadow-red-600/30 font-black text-sm active:scale-95">
              <PrinterIcon className="w-5 h-5" /> EXPORTAR PDF / IMPRIMIR
            </button>
          </div>
        </div>
        <div className="max-w-[210mm] mx-auto my-16 shadow-[0_0_100px_rgba(227,6,19,0.15)] ring-1 ring-white/10 rounded-sm overflow-hidden bg-white">
          <ReportPreview data={data} />
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#0a0a0a] text-white selection:bg-[#E30613] selection:text-white font-sans">
      <input type="file" ref={fileInputRef} onChange={importDB} accept=".json" className="hidden" />

      {/* Mesh Gradient Background */}
      <div className="fixed inset-0 pointer-events-none z-0 overflow-hidden">
        <div className="absolute top-[-15%] right-[-10%] w-[60%] h-[60%] bg-[#E30613]/5 blur-[120px] rounded-full animate-pulse" />
        <div className="absolute bottom-[-10%] left-[-10%] w-[40%] h-[40%] bg-blue-900/5 blur-[120px] rounded-full" />
      </div>

      <div className="relative z-10 flex flex-col md:flex-row min-h-screen">
        {/* Modern Nav Sidebar */}
        <aside className="w-full md:w-72 bg-black/40 border-r border-white/5 backdrop-blur-xl flex flex-col p-6 sticky top-0 h-auto md:h-screen">
          <div className="mb-12 px-2">
            <SmartTechLogo light className="h-12" />
          </div>

          <nav className="flex-1 space-y-1.5">
            <NavItem active={activeTab === 'Geral'} onClick={() => setActiveTab('Geral')} icon={<HomeIcon />} label="Dashboard" />
            <NavItem active={activeTab === 'Partes'} onClick={() => setActiveTab('Partes')} icon={<BuildingOfficeIcon />} label="Contratantes" />
            <NavItem active={activeTab === 'Licencas'} onClick={() => setActiveTab('Licencas')} icon={<CpuChipIcon />} label="Licenças" />
