            <div className="pt-6 pb-2 px-4 text-[10px] font-black text-white/20 uppercase tracking-[0.2em]">Gestão de Dados</div>
            <NavItem active={activeTab === 'Banco'} onClick={() => setActiveTab('Banco')} icon={<ArchiveBoxIcon />} label="Banco de Termos" />
          </nav>

          <div className="mt-auto pt-6 border-t border-white/5 space-y-3">
            <button onClick={exportDB} className="w-full flex items-center justify-center gap-2 py-3 bg-white/5 hover:bg-white/10 border border-white/5 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all">
              <ArrowDownTrayIcon className="w-4 h-4" /> Exportar Backup
            </button>
            <button onClick={() => fileInputRef.current?.click()} className="w-full flex items-center justify-center gap-2 py-3 bg-white/5 hover:bg-white/10 border border-white/5 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all">
              <ArrowUpTrayIcon className="w-4 h-4" /> Importar Backup
