              <p className="text-white/40 text-sm font-medium">
                {activeTab === 'Banco' ? `Existem ${savedReports.length} relatórios salvos localmente` : `Termo Nº ${data.reportNumber} - ${data.contratante.name}`}
              </p>
            </div>

            <div className="flex gap-4">
