                            </div>
                          </div>
                          <button onClick={() => handleUpdate('items', data.items.filter(i => i.id !== item.id))} className="absolute top-6 right-6 p-3 bg-red-600/10 text-red-500 hover:bg-red-600 hover:text-white rounded-2xl transition-all opacity-0 group-hover:opacity-100">
                            <TrashIcon className="w-5 h-5" />
                          </button>
                        </div>
                      ))}
                    </div>
                  </div>
                )}

