                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                      <FormInput label="Responsável Técnico" value={data.techResponsible.name} onChange={v => handleUpdate('techResponsible.name', v)} />
                      <FormInput label="URL de Acesso" value={data.installation.accessLink} onChange={v => handleUpdate('installation.accessLink', v)} />
