};

const NavItem: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string }> = ({ active, onClick, icon, label }) => (
  <button onClick={onClick} className={`w-full flex items-center gap-4 px-6 py-4 rounded-[20px] transition-all duration-300 group ${active ? 'bg-gradient-to-r from-red-600 to-red-500 text-white font-bold shadow-xl shadow-red-600/20' : 'text-white/30 hover:text-white hover:bg-white/5'}`}>
    <div className={`w-5 h-5 transition-transform group-hover:scale-110 ${active ? 'scale-110' : ''}`}>{icon}</div>
    <span className="text-sm tracking-tight">{label}</span>
  </button>
);

const CardSection: React.FC<{ title: string; description: string; children: React.ReactNode }> = ({ title, description, children }) => (
  <div className="bg-white/5 border border-white/5 p-12 rounded-[56px] shadow-2xl backdrop-blur-3xl animate-in fade-in slide-in-from-bottom-2 duration-500">
    <div className="mb-12">
