      <p className="text-sm text-white/30 font-medium">{description}</p>
    </div>
    {children}
  </div>
);

const FormInput: React.FC<{ label: string; value: string; onChange: (v: string) => void; type?: string; placeholder?: string }> = ({ label, value, onChange, type = "text", placeholder }) => (
  <div className="flex flex-col gap-3">
    <label className="text-[10px] font-black uppercase tracking-[0.2em] opacity-30 ml-2">{label}</label>
    <input 
      type={type} 
      value={value} 
      onChange={e => onChange(e.target.value)} 
      placeholder={placeholder}
      className="bg-black/40 border border-white/5 rounded-2xl px-6 py-4.5 text-sm text-white focus:border-red-500/50 outline-none transition-all focus:ring-4 ring-red-500/5 placeholder:text-white/10" 
    />
  </div>
);

export default App;

