    const hash = window.location.hash;
    if (hash && hash.startsWith('#data=')) {
      try {
        const encodedData = hash.replace('#data=', '');
        const decodedData = JSON.parse(atob(encodedData));
        setData(decodedData);
        // Limpa a URL após carregar para evitar bugs de navegação
        window.history.replaceState(null, '', window.location.pathname);
        alert("Dados carregados com sucesso via link de compartilhamento!");
      } catch (e) {
        console.error("Erro ao decodificar link:", e);
      }
    }

    const stored = localStorage.getItem(DB_KEY);
    if (stored) {
      try {
        setSavedReports(JSON.parse(stored));
      } catch (e) { console.error(e); }
    }
  }, []);

  const saveToDatabase = () => {
    setSaveStatus('saving');
    const updatedReports = [...savedReports];
    const index = updatedReports.findIndex(r => r.id === data.id);
    index >= 0 ? (updatedReports[index] = data) : updatedReports.unshift(data);
    localStorage.setItem(DB_KEY, JSON.stringify(updatedReports));
    setSavedReports(updatedReports);

