    navigator.clipboard.writeText(url);
    alert("Link de backup gerado e copiado! Salve este link para acessar este termo de qualquer lugar.");
  };

  const handlePrint = () => {
    const originalTitle = document.title;
    const fileName = `Termo_${data.reportNumber.replace(/\//g, '-')}_${data.contratante.name.replace(/[^a-z0-9]/gi, '_').substring(0, 25)}`;
